sql:
SELECT initiative_type, COUNT(*) AS number_of_initiatives
FROM community_initiatives
GROUP BY initiative_type;

SELECT COUNT(*) 
FROM community_areas 
WHERE median_home_value > (SELECT AVG(median_home_value) FROM community_areas);

SELECT community_id, AVG(resident_income) AS average_income
FROM community_residents
GROUP BY community_id;

SELECT service_name, service_type
FROM community_services
WHERE service_type = 'healthcare';

SELECT COUNT(resident_id) AS total_residents, AVG(resident_income) AS average_income
FROM community_residents
WHERE community_id = 1;

SELECT community_id, AVG(resident_income) AS average_income
FROM community_residents
WHERE community_id = 1;

SELECT area_code, AVG(median_home_value) AS avg_home_value, SUM(population) AS total_population
FROM community_areas
GROUP BY area_code;

SELECT COUNT(*) AS number_of_businesses
FROM community_businesses
WHERE community_id = 0;

SELECT COUNT(service_id) AS total_services
FROM community_services
WHERE community_id = 1;

SELECT contact_name, contact_email
FROM community_contacts
WHERE contact_phone IS NOT NULL;

SELECT issue_id, issue_type, issue_description
FROM community_issues
WHERE status = 'in progress';
